    10â†’// LLMModel represents a language model in the registry
    11â†’type LLMModel struct {
    12â†’	ID           string            `json:"id"`           // e.g., "gpt-4o-mini@2024-08-06"
    13â†’	Name         string            `json:"name"`         // Display name
    14â†’	Provider     string            `json:"provider"`     // openai, anthropic, azure, local
    15â†’	Version      string            `json:"version"`      // Model version
    16â†’	Capabilities []string          `json:"capabilities"` // ["code", "analysis", "planning"]
    17â†’	Config       map[string]string `json:"config"`       // Provider-specific config
    18â†’	MaxTokens    int               `json:"max_tokens"`   // Context window size
    19â†’	CostPerToken float64           `json:"cost_per_token,omitempty"`
    20â†’	Created      Time              `json:"created"`
    21â†’	Updated      Time              `json:"updated"`
    22â†’}
    23â†’
    24â†’// ValidProviders lists supported model providers
    25â†’var ValidProviders = []string{"openai", "anthropic", "azure", "local"}
    26â†’
    27â†’// ValidCapabilities lists supported model capabilities
    28â†’var ValidCapabilities = []string{"code", "analysis", "planning", "reasoning", "multimodal", "function_calling"}
