    33â†’// Validate validates the LLM model data
    34â†’func (m *LLMModel) Validate() error {
    35â†’	// Required fields
    36â†’	if m.ID == "" {
    37â†’		return fmt.Errorf("model ID is required")
    38â†’	}
    39â†’	if m.Name == "" {
    40â†’		return fmt.Errorf("model name is required")
    41â†’	}
    42â†’	if m.Provider == "" {
    43â†’		return fmt.Errorf("model provider is required")
    44â†’	}
    45â†’	if len(m.Capabilities) == 0 {
    46â†’		return fmt.Errorf("at least one capability is required")
    47â†’	}
    48â†’
    49â†’	// Validate ID format
    50â†’	if !ModelIDPattern.MatchString(m.ID) {
    51â†’		return fmt.Errorf("invalid model ID format: %s (should match pattern: provider@version or provider/model@version)", m.ID)
    52â†’	}
    53â†’
    54â†’	// Validate provider
    55â†’	if !isValidProvider(m.Provider) {
    56â†’		return fmt.Errorf("invalid provider: %s (supported: %s)", m.Provider, strings.Join(ValidProviders, ", "))
    57â†’	}
    58â†’
    59â†’	// Validate capabilities
    60â†’	for _, capability := range m.Capabilities {
    61â†’		if !isValidCapability(capability) {
    62â†’			return fmt.Errorf("invalid capability: %s (supported: %s)", capability, strings.Join(ValidCapabilities, ", "))
    63â†’		}
    64â†’	}
    65â†’
    66â†’	// Validate numeric fields
    67â†’	if m.MaxTokens <= 0 {
    68â†’		return fmt.Errorf("max_tokens must be greater than 0")
    69â†’	}
    70â†’	if m.CostPerToken < 0 {
    71â†’		return fmt.Errorf("cost_per_token cannot be negative")
    72â†’	}
    73â†’
    74â†’	return nil
    75â†’}
